def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            base = np.exp(ratio - 10)
            for a in range(5, 0, -1):
                for b in range(1, a + 5):
                    blend = ((ratio - a) ** 6) / (a * b * 0.7 + 0.5)
                    priority += blend * np.cos(ratio * b / (a + 0.5)) * np.sin(ratio / (b + 1))
            priority += (base * np.sin(ratio * 1.3)) ** 2 + np.log1p(ratio) * 7
        elif 6 < ratio <= 10:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.8) / (q + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 6) * 3
        elif 3 < ratio <= 6:
            s1, s2 = 0, 0
            for r1 in range(1, 15):
                s1 += ((ratio - 3) ** r1) / (r1 * 2.1) * np.sin(r1 * ratio * 0.9)
            for r2 in range(1, 10):
                s2 += ((ratio - 3) ** (r2 / 2)) / (r2 + 1) * np.cos(r2 * ratio)
            priority = (s1 * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (6 - ratio)) * 2 + s2 * 0.5
        elif 1.5 <= ratio <= 3:
            s = 0
            for n in range(1, 20):
                s += ((ratio - 1.5) ** n) / (n ** 1.5 + 0.3) * np.sin(n * ratio * 1.1)
            priority = s - np.log(ratio) * 8 + np.tanh(3.5 * (3 - ratio)) * 2.5
            for m in range(1, 7):
                priority += np.cos(m * ratio * i) * ((ratio - 1.5) ** m) / (m ** 0.8 + 1)
        elif 0.9 <= ratio < 1.5:
            s = 0
            for k in range(1, 15):
                s += ((1.5 - ratio) ** k) / (k ** 2 + 1) * np.tanh(k * ratio * 1.2)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.03))
            for l in range(1, 6):
                addendum = np.sin(l * ratio * i) * ((ratio - 0.9) ** l) / (l + 0.5)
                priority += addendum
        elif 0.4 <= ratio < 0.9:
            s = 0
            for n in range(1, 20):
                s += ((0.9 - ratio) ** n) / (n * 3.5) * np.cos(n * item * 1.1)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 8):
                priority += ((0.9 - ratio) ** j) * np.sin(j * item * 1.3) * 0.8
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
